import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [filteredJobs, setFilteredJobs] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setFilteredJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error(err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  useEffect(() => {
    const results = jobs.filter(job =>
      job.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      job.loc.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setFilteredJobs(results);
  }, [searchTerm, jobs]);

  return (
    <div className="bg-[#fcfcfc] min-h-screen font-sans">

      {/* --- HERO SECTION WITH SEARCH --- */}
      <section className="pt-40 pb-20 px-8 max-w-7xl mx-auto text-center">
        <h2 className="text-7xl font-black text-gray-950 tracking-tighter mb-8">
          Work with <span className="text-orange-600">Hudson</span>
        </h2>

        {/* MODERN SEARCH BAR */}
        <div className="max-w-2xl mx-auto relative group">
          <div className="absolute inset-0 bg-orange-500/5 blur-2xl rounded-full group-hover:bg-orange-500/10 transition-all duration-500"></div>
          <div className="relative flex items-center bg-white border border-gray-100 shadow-[0_20px_50px_rgba(0,0,0,0.04)] rounded-full px-8 py-2 focus-within:border-orange-500/30 transition-all">
            <span className="text-xl mr-4 opacity-30">🔍</span>
            <input 
              type="text"
              placeholder="Search by role or location..."
              className="w-full py-4 text-lg bg-transparent outline-none text-gray-700 placeholder:text-gray-300 font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            {searchTerm && (
              <button 
                onClick={() => setSearchTerm('')}
                className="ml-4 text-gray-400 hover:text-gray-950 text-sm font-bold"
              >
                CLEAR
              </button>
            )}
          </div>
        </div>
      </section>

      {/* --- JOBS BOARD --- */}
      <section className="px-8 max-w-6xl mx-auto pb-32">

        {/* HEADERS */}
        <div className="hidden md:flex items-center px-10 py-6 border-b border-gray-100 mb-2">
          <div className="w-[45%] text-[10px] font-black uppercase tracking-[0.3em] text-gray-400">Position</div>
          <div className="w-[25%] text-[10px] font-black uppercase tracking-[0.3em] text-gray-400">Location</div>
          <div className="w-[15%] text-[10px] font-black uppercase tracking-[0.3em] text-gray-400">Salary</div>
          <div className="w-[15%]"></div>
        </div>

        {/* LISTING */}
        <div className="divide-y divide-gray-50">
          {loading ? (
            <div className="py-20 text-center font-black text-gray-200 tracking-tighter text-4xl animate-pulse">LOADING...</div>
          ) : filteredJobs.length > 0 ? (
            filteredJobs.map((job) => (
              <div key={job._id} className="group flex flex-col md:flex-row md:items-center px-10 py-12 hover:bg-white hover:shadow-[0_15px_40px_rgba(0,0,0,0.03)] rounded-[2rem] transition-all duration-500">

                {/* 1. Title (Not Bold) */}
                <div className="w-full md:w-[45%] mb-4 md:mb-0">
                  <h3 className="text-2xl text-gray-800 font-normal tracking-tight group-hover:text-orange-600 transition-colors">
                    {job.title}
                  </h3>
                </div>

                {/* 2. Location */}
                <div className="w-full md:w-[25%] mb-4 md:mb-0">
                  <p className="text-gray-500 text-sm font-semibold flex items-center gap-2">
                    <span className="w-1.5 h-1.5 bg-orange-500 rounded-full"></span>
                    {job.loc}
                  </p>
                </div>

                {/* 3. Salary */}
                <div className="w-full md:w-[15%] mb-6 md:mb-0">
                  <p className="text-gray-400 text-sm font-medium italic">{job.salary}</p>
                </div>

                {/* 4. Action */}
                <div className="w-full md:w-[15%] text-left md:text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-8 py-4 rounded-full font-black text-[10px] uppercase tracking-widest hover:bg-orange-600 hover:shadow-xl hover:shadow-orange-200 transition-all"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="py-24 text-center">
              <p className="text-gray-400 font-medium">No matches found for "{searchTerm}"</p>
            </div>
          )}
        </div>
      </section>

      {/* Modal section remains same */}
    </div>
  );
};

export default Careers;
